---@param spineDp LxSpineDp
function LCityEventArea:OnLoadModel(spineDp)
    local trans = spineDp:GetDpTrans()
    if not trans then return end
    trans.name = self._eventData.id
    self:InitEventAreaCom(trans)
    self:UpdateShow()
end

function LCityEventArea:InitEventAreaCom(trans)
    local go = trans.gameObject
    local com = go:GetComponent(typeOfEventAreaObject)
    if not com then
        com = go:AddComponent(typeOfEventAreaObject)
    end
    com.eventId = self._eventData.id
end

